public class User {
    private final String name;
    private final int age;

    public User(String name, int age) {
        this.name = name;
        this.age = age;
    }

    public boolean isAdult() { return age >= 18; }

    @Override
    public String toString() {
        return name + " (" + age + ")";
    }
}
